import { _decorator } from 'cc';
import { BaseSpine } from './BaseSpine';
import { Define } from 'db://astarte-framework/utilis';
const { ccclass, property } = _decorator;

@ccclass('InLoopOutSpine')
export class InLoopOutSpine extends BaseSpine {
    @property({
        type: String,
        tooltip: "進場動畫名稱"
    })
    private m_enterAnimationName: string = "In";

    @property({
        type: String,
        tooltip: "循環動畫名稱"
    })
    private m_loopAnimationName: string = "Loop";

    @property({
        type: String,
        tooltip: "退場動畫名稱"
    })
    private m_exitAnimationName: string = "Out";

    /**@ch 是否正在播放 */
    private m_isPlaying: boolean = false;

    /**
     * @ch 設定進場動畫名稱
     * @param enterAnimationName 進場動畫名稱
     */
    SetEnterAnimationName(enterAnimationName: string)
    {
        this.m_enterAnimationName = enterAnimationName;
    }

    /**
     * @ch 設定循環動畫名稱
     * @param loopAnimationName 循環動畫名稱
     */
    SetLoopAnimationName(loopAnimationName: string)
    {
        this.m_loopAnimationName = loopAnimationName;
    }

    /**
     * @ch 設定退場動畫名稱
     * @param exitAnimationName 退場動畫名稱
     */
    SetExitAnimationName(exitAnimationName: string)
    {
        this.m_exitAnimationName = exitAnimationName;
    }

    /**
     * @ch 播放進場動畫
     * @param trackIdx 軌道索引
     * @param enterFinishCallback 進場動畫完成後回調
     * @param isAutoStop 是否自動停止 預設為true
     * 如果isAutoStop為true，則播放進場動畫並等待進場動畫完成後播放循環動畫，並在循環動畫完成後播放退場動畫
     * 如果isAutoStop為false，則播放進場動畫並等待進場動畫完成後播放循環動畫，並不會播放退場動畫
     * @param eventCb 動畫事件回調
     * @returns 
     */
    async PlayInLoop(trackIdx: number = 0, enterFinishCallback?: () => void, isAutoStop: boolean = true, eventCb?: (eventName: string) => void) : Promise<void>
    {
        if (this.m_isPlaying) return;
        this.m_isPlaying = true;
        this.SetNodeActivity(true);
        this.SetSpineNodeActivity(true);
        await this.PlayAnimation(this.m_enterAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
        enterFinishCallback?.();
        await this.PlayAnimation(this.m_loopAnimationName, this.m_spine, true, 1, eventCb, trackIdx);
        if (isAutoStop)
        {
            await this.PlayOut(trackIdx);
        }
    }

    /**
     * @ch 播放進場動畫
     * @param trackIdx 軌道索引
     * @param enterFinishCallback 進場動畫完成後回調
     * @param eventCb 動畫事件回調
     * @returns 
     */
    async PlayIn(trackIdx: number = 0, enterFinishCallback?: () => void, eventCb?: (eventName: string) => void) : Promise<void>
    {
        if (this.m_isPlaying) return;
        this.m_isPlaying = true;
        this.SetNodeActivity(true);
        this.SetSpineNodeActivity(true);
        await this.PlayAnimation(this.m_enterAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
        enterFinishCallback?.();
    }

    /**
     * @ch 播放循環動畫
     * @param trackIdx 軌道索引
     * @param loopFinishCallback 循環動畫完成後回調
     * @param eventCb 動畫事件回調
     * @returns 
     */
    async PlayLoop(trackIdx: number = 0, loopFinishCallback?: () => void, eventCb?: (eventName: string) => void) : Promise<void>
    {
        this.m_isPlaying = true;
        this.SetNodeActivity(true);
        this.SetSpineNodeActivity(true);
        await this.PlayAnimation(this.m_loopAnimationName, this.m_spine, true, 1, eventCb, trackIdx);
        loopFinishCallback?.();
    }

    /**
     * @ch 播放退場動畫
     * @param trackIdx 軌道索引
     * @param outPlayDuration 退場動畫播放時間（秒）
     * 如果退場動畫播放時間大於0，則播放退場動畫並等待退場動畫播放時間後停止
     * 如果退場動畫播放時間小於0，則播放退場動畫並等待動畫完成後停止
     * @param outStopCallback 退場動畫完成後回調
     * @returns 
     */
    async PlayOut(trackIdx: number = 0, outPlayDuration: number = -1, outStopCallback: () => void = () => {}, eventCb?: (eventName: string) => void) : Promise<void>
    {
        if (!this.m_isPlaying) return;
        this.SetNodeActivity(true);
        this.SetSpineNodeActivity(true);
        if (outPlayDuration > 0) {
            this.PlayAnimation(this.m_exitAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
            await Define.Wait(this, outPlayDuration);
            this.Stop();
        }
        else {
            await this.PlayAnimation(this.m_exitAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
        }
        this.SetNodeActivity(false);
        this.SetSpineNodeActivity(false);
        this.m_isPlaying = false;
        outStopCallback?.();
    }

    /**
     * @ch 強制停止動畫
     */
    ForceStop()
    {
        this.Stop();
        this.SetNodeActivity(false);
        this.SetSpineNodeActivity(false);
        this.m_isPlaying = false;
    }
}

