import { _decorator, Component, error, Label } from 'cc';
import { InLoopOutSpine } from '../Spine/InLoopOutSpine';
import { eventManager } from 'db://astarte-framework/Managers';
import { Define } from 'db://astarte-framework/utilis';
import { Common } from '../Common/Common';
import GameView from '../GameView';

const { ccclass, property } = _decorator;

/**@ch 免費遊戲進場事件 */
export const FREE_GAME_INTRO_EVENT = {
    /**
     * @ch 播放進場動畫（In → Loop → 等待 → Out）
     * @param totalRound 獲得 FreeGame 的總回合數
     * @param (選填) callback 完成後回調
     */
    PLAY: "FREE_GAME_INTRO_PLAY",
}

/** 動畫事件名稱（Spine 動畫內嵌的事件標記） */
const AnimEvent = {
    /**@ch 進場動畫觸發：隱藏其他 UI */
    HideOtherUI: "MG_Off",
    /**@ch 退場動畫觸發：顯示其他 UI */
    ShowOtherUI: "FG_On",
} as const;

/** 動畫名稱：H = 橫版, S = 直版 */
const AnimName = {
    /**@ch 進場動畫 */
    Enter: { H: "In_H", S: "In_S" },
    /**@ch 循環動畫 */
    Loop: { H: "Loop_H", S: "Loop_S" },
    /**@ch 退場動畫 */
    Out: { H: "Out_H", S: "Out_S" },
} as const;

/**@ch 免費遊戲進場演出 */
@ccclass('FreeGameIntro')
export class FreeGameIntro extends Component {
    //#region Constants
    /**@ch 需要註冊的事件列表 */
    private static readonly EVENTS_TO_REGISTER = [
        FREE_GAME_INTRO_EVENT.PLAY,
    ];
    //#endregion Constants

    //#region Properties
    @property({
        type: InLoopOutSpine,
        tooltip: "進場動畫 Spine（控制 In / Loop / Out）"
    })
    private m_introSpine: InLoopOutSpine = null;

    @property({
        tooltip: "Loop 循環等待時間（秒），時間到後播放 Out"
    })
    private m_loopDuration: number = 2;

    @property({
        type: Label,
        tooltip: "顯示獲得 FreeGame 的總回合數"
    })
    private m_totalRoundLabel: Label = null;
    //#endregion Properties

    //#region Variables
    /**@ch 是否已註冊事件 */
    private m_isEventRegistered: boolean = false;

    /**@ch 是否正在播放進場 */
    private m_isPlaying: boolean = false;

    /**@ch 遊戲視圖 */
    private m_gameView: GameView = null;
    //#endregion Variables

    //#region Lifecycle
    onLoad() {
        this.RegisterEvent();
    }

    onDestroy() {
        this.UnregisterEvent();
        this.m_gameView = null;
    }
    //#endregion Lifecycle

    //#region Event
    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        if (this.m_isEventRegistered) return;
        FreeGameIntro.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });
        this.m_isEventRegistered = true;
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() {
        if (!this.m_isEventRegistered) return;
        FreeGameIntro.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });
        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件處理器
     * @param event 事件名稱
     * @param args 參數
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case FREE_GAME_INTRO_EVENT.PLAY:
                this.PlayIntro(args[0], args[1]);
                break;
        }
    }
    //#endregion Event

    //#region Methods
    /**
     * @ch 取得遊戲視圖（惰性快取）
     * @returns 遊戲視圖，取不到時回傳 null
     */
    private GetGameView(): GameView {
        if (!this.m_gameView) {
            this.m_gameView = Common.GetGameView();
        }
        return this.m_gameView;
    }

    /**
     * @ch 是否為直版
     * @returns 是否為直版
     */
    private IsPortrait(): boolean {
        const gameView = this.GetGameView();
        if (!gameView) return false;
        return !gameView.IsLandscape;
    }

    /**
     * @ch 播放進場動畫：In（一次）→ Loop（循環）→ 等待 m_loopDuration 秒 → Out
     * @param callback 完成後回調
     */
    private async PlayIntro(callback?: () => void): Promise<void> {
        if (this.m_isPlaying) return;
        if (!this.m_introSpine) {
            error('[FreeGameIntro] m_introSpine is null, cannot play intro');
            callback?.();
            return;
        }

        this.m_isPlaying = true;
        try {
            // 依橫/直版覆寫三段動畫名稱
            const orient = this.IsPortrait() ? 'S' : 'H';
            this.m_introSpine.SetEnterAnimationName(AnimName.Enter[orient]);
            this.m_introSpine.SetLoopAnimationName(AnimName.Loop[orient]);
            this.m_introSpine.SetExitAnimationName(AnimName.Out[orient]);

            // 進場動畫；動畫播到 "MG_Off" 事件時隱藏其他 UI
            await this.m_introSpine.PlayIn(0, undefined, (eventName: string) => {
                if (eventName === AnimEvent.HideOtherUI) {
                    this.GetGameView()?.SetOtherUIShow(false);
                }
            });                                              // In_H / In_S，await 到進場完成
            this.m_introSpine.PlayLoop();                    // Loop_H / Loop_S，開始循環（不 await）
            await Define.Wait(this, this.m_loopDuration);    // 等待可設定的秒數
            // 退場動畫；動畫播到 "FG_On" 事件時顯示其他 UI
            await this.m_introSpine.PlayOut(0, -1, undefined, (eventName: string) => {
                if (eventName === AnimEvent.ShowOtherUI) {
                    this.GetGameView()?.SetOtherUIShow(true);
                }
            });                                              // Out_H / Out_S
        } catch (err) {
            error('[FreeGameIntro] PlayIntro error:', err);
            this.m_introSpine.ForceStop();
        } finally {
            this.m_isPlaying = false;
            callback?.();
        }
    }
    //#endregion Methods
}

import { _decorator, error, log } from "cc";
import { stateManager, BaseState, newBottombarManager, eventManager, SlotBottomBarState } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";
import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
import { FREE_GAME_INTRO_EVENT } from "../FreeGame/FreeGameIntro";
import { Common } from "../Common/Common";
import { WheelDataLayer, HasFreeGameWheel } from "../FeatureWheel/FeatureWheelTypes";
import { FEATURE_MARK_EVENT } from "../FeatureWheel/FeatureMarkEvent";

const { ccclass } = _decorator;

// 進入免費遊戲狀態前的初始等待時間
const ENTER_FREE_INITIAL_DELAY_SECONDS = 1.5;

@ccclass( "EnterFreeState" )
export class EnterFreeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State : ENTER_FREE" );

        await Define.Wait(this.m_gameView, ENTER_FREE_INITIAL_DELAY_SECONDS);

        // 暫停主遊戲背景音樂
        this.m_gameView.PauseMainGameBgm();

        newBottombarManager.SetEnterFree();
        this.StopEffect();
        this.m_gameView.IsFreeGame = true;

        // FeatureWheel 轉盤資料切到 FG 層（否則 FG round 轉輪演出沿用 MG 版面 icon）
        this.m_gameView.SetFeatureWheelLayer( WheelDataLayer.FreeGame );

        // FG 不沿用 MG 輪盤的標記：進 FG 一律清空持久標記，FG 期間只吃自己每手的 RoundInfo
        // （FG 自己那手的輪盤功能照常走 AfterShowWin → FeatureWheelShowState）。
        this.m_gameView.FGPersistentWheelFeatures = [];

        // ⑨Scatter丟場 seam：MG 轉輪落 FreeGame → 進 FG 前丟 Scatter 補齊觸發
        if ( HasFreeGameWheel( this.m_gameView.RoundInfo?.WheelFeatures?.map( w => w.Type ) ) )
        {
            await new Promise<void>( resolve =>
            {
                eventManager.Dispatch( FEATURE_MARK_EVENT.SHOW_SCATTER_DROP, () => resolve() );
            } );
        }

        newBottombarManager.SetBarNodeVisiable( false );
        this.m_gameView.BuyBonus?.SetBuyBtnVisible( false );        

        // 鎖定方向
        Common.SetLockOrientation(true);

        // 播放免費遊戲進場演出
        await this.PlayFreeGameEnterAnim();

        // 播放免費遊戲音樂
        this.m_gameView.PlayFreeGameBgm();

        // 準備進入免費遊戲
        newBottombarManager.SetBarNodeVisiable(true);

        // 顯示免費遊戲回合數字
        eventManager.Dispatch(FREE_GAME_ROUND_UI_EVENT.SHOW);

        // 各遊戲須自己處理自動玩
        if ( newBottombarManager.IsAutoSpin )
        {
            if ( this.m_gameView.AutoplayInfos.isCheckFree )
            {
                newBottombarManager.ShowAutoPlayState( false );
                newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                this.m_gameView.IsFirstRound = true;
            }
            else
            {
                this.m_gameView.IsFirstRound = false;
            }
        }
        else
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
            this.m_gameView.IsFirstRound = true;
        }

        // NextState
        stateManager.NextState( Game_Define.GameState.ROUND_END );
    }

    public OnProcess( dt: number = 0 )
    {

    }

    public OnLeave()
    {
        // 解除鎖定
        Common.SetLockOrientation(false);
    }

    /**
     * @ch 播放免費遊戲進場演出
     * @returns 
     */
    private async PlayFreeGameEnterAnim() : Promise<void>
    {
        // 初始化免費遊戲回合數字
        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, 0, this.m_gameView.RoundInfo.FreeTotalRound );

        // 更新背景
        this.m_gameView.CheckBackground();

        // 進場演出（依賴 FG 場景中已註冊的 FreeGameIntro 元件回呼 callback，否則此 await 不會結束）
        await new Promise<void>( resolve =>
        {
            eventManager.Dispatch( FREE_GAME_INTRO_EVENT.PLAY, () => resolve() );
        } );
    }

    /**
     * @ch 停止效果
     */
    private StopEffect()
    {
        this.m_gameView.EffectPlate.StopOneLineShow();
        this.m_gameView.ClearAll();
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
    }
}

